import { Kernel } from '@semantic-kernel/core';
import { SemanticTextMemory } from '@semantic-kernel/memory';

class MemoryDriftDetector {
  private memory: SemanticTextMemory;
  private threshold = 0.7;

  constructor(kernel: Kernel) {
    this.memory = kernel.memory;
  }

  async detectHallucination(
    recalled: string, 
    actualHistory: string[]
  ): Promise<boolean> {
    const { OpenAIEmbedding } = await import('@semantic-kernel/connectors-ai-openai');

    const embeddingGen = new OpenAIEmbedding('text-embedding-ada-002', 'your-api-key');

    const recalledEmbedding = await embeddingGen.generateEmbedding(recalled);
    const historyEmbeddings = await Promise.all(
      actualHistory.map(h => embeddingGen.generateEmbedding(h))
    );

    const similarities = historyEmbeddings.map(
      emb => this.cosineSimilarity(recalledEmbedding, emb)
    );

    return Math.max(...similarities) < this.threshold;
  }

  private cosineSimilarity(a: number[], b: number[]): number {
    const dot = a.reduce((sum, val, i) => sum + val * b[i], 0);
    const magA = Math.sqrt(a.reduce((sum, val) => sum + val * val, 0));
    const magB = Math.sqrt(b.reduce((sum, val) => sum + val * val, 0));
    return dot / (magA * magB);
  }
}
