import { Kernel } from '@semantic-kernel/core';

class IsolatedContextManager {
  private kernel: Kernel;

  constructor(kernel: Kernel) {
    this.kernel = kernel;
  }

  async invokeIsolated(
    pluginName: string, 
    functionName: string, 
    input: any
  ): Promise<any> {
    // Create isolated context
    const isolatedContext = this.kernel.createNewContext();

    // Clear any shared variables
    isolatedContext.variables.clear();

    // Set only required input
    isolatedContext.variables.set('input', JSON.stringify(input));

    try {
      const result = await this.kernel.invoke(
        pluginName, 
        functionName, 
        isolatedContext
      );

      return {
        success: true,
        result: result,
        contextIsolated: true
      };
    } catch (error) {
      return {
        success: false,
        error: error.message,
        contextIsolated: true
      };
    }
  }
}
